-- This file allow to write SQL commands that will be emitted in test and dev.
--
-- Atenção: com quarkus.hibernate-orm.schema-management.strategy=update o Quarkus
-- NÃO executa este import.sql automaticamente. Use-o como script de carga (seed)
-- executando manualmente no Postgres, ou alterando temporariamente a estratégia.
-- Os inserts são idempotentes (ON CONFLICT DO NOTHING), seguros para reexecução.

-- Tabela VAU - valores de referência por estado/destinacao - Periodo: Junho/2026 (2026-06)
on conflict (periodo, estado) do nothing;
